3	function isNeighbor(cell: Cell, other: Cell): boolean {
4	  const sameCell = other[0] === cell[0] && other[1] === cell[1];
5	  return (
6	    !sameCell &&
7	    Math.abs(other[0] - cell[0]) <= 1 &&
8	    Math.abs(other[1] - cell[1]) <= 1
9	  );
10	}
