12	function countNeighbors(cell: Cell, cells: Cell[]): number {
13	  return cells.filter((other) => isNeighbor(cell, other)).length;
14	}
15	
16	function isLive(cell: Cell, cells: Cell[]): boolean {
17	  return cells.some(
18	    (other) => other[0] === cell[0] && other[1] === cell[1],
19	  );
20	}
