22	export function nextGeneration(cells: Cell[]): Cell[] {
23	  const survivors = cells.filter((cell) => {
24	    const neighborCount = countNeighbors(cell, cells);
25	    return neighborCount === 2 || neighborCount === 3;
26	  });
27	
28	  const births: Cell[] = [];
29	  for (const cell of cells) {
30	    for (let dx = -1; dx <= 1; dx++) {
31	      for (let dy = -1; dy <= 1; dy++) {
32	        const candidate: Cell = [cell[0] + dx, cell[1] + dy];
33	        if (isLive(candidate, cells)) continue;
34	        if (isLive(candidate, births)) continue;
