1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (no neighbors) [(0,0)] -> []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill live cells with fewer than 2 neighbors [(0,1),(1,1)] -> [] (Rule 1: underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell with 2 or 3 neighbors alive (Rule 2: survival)", () => {
15	    // Gen 0 cross/T shape: ### / ... / .#.  → live cell (1,0) has 2 neighbors (0,0),(2,0) and survives
16	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 2]]);
17	    expect(result).toContainEqual([1, 0]);
18	  });
19	  it("should kill a live cell with more than 3 neighbors (Rule 3: overpopulation)", () => {
20	    // Gen 0: ### / .#. / ###  → center cell (1,1) has >3 live neighbors and dies
21	    const result = nextGeneration([
22	      [0, 0], [1, 0], [2, 0],
23	      [1, 1],
24	      [0, 2], [1, 2], [2, 2],
25	    ]);
26	    expect(result).not.toContainEqual([1, 1]);
27	  });
28	  it("should bring a dead cell with exactly 3 neighbors to life (Rule 4: reproduction)", () => {
29	    // Gen 0: ## . / # . . / . . .  → dead cell (1,1) has exactly 3 live neighbors (0,0),(1,0),(0,1) and becomes alive
30	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
31	    expect(result).toContainEqual([1, 1]);
32	  });
