function isLive(cell: Cell, cells: Cell[]): boolean {
  return cells.some(
    (other) => other[0] === cell[0] && other[1] === cell[1],
  );
}

export function nextGeneration(cells: Cell[]): Cell[] {
  const survivors = cells.filter((cell) => {
    const neighborCount = countNeighbors(cell, cells);
    return neighborCount === 2 || neighborCount === 3;
  });

  const births: Cell[] = [];
  for (const cell of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const candidate: Cell = [cell[0] + dx, cell[1] + dy];
        if (isLive(candidate, cells)) continue;
        if (isLive(candidate, births)) continue;
        if (countNeighbors(candidate, cells) === 3) {
          births.push(candidate);
        }
      }
    }
  }

  return [...survivors, ...births];
}

