function isLive(cell: Cell, cells: Cell[]): boolean {
  return cells.some((other) => isNeighbor(cell, other) === false && other[0] === cell[0] && other[1] === cell[1]) ||
    cells.some((other) => other[0] === cell[0] && other[1] === cell[1]);
}

function deadNeighborCandidates(cells: Cell[]): Cell[] {
  const offsets = [-1, 0, 1];
  const candidates: Cell[] = [];
  for (const cell of cells) {
    for (const dx of offsets) {
      for (const dy of offsets) {
        const candidate: Cell = [cell[0] + dx, cell[1] + dy];
        if (isLive(candidate, cells)) continue;
        if (isLive(candidate, candidates)) continue;
        candidates.push(candidate);
      }
    }
  }
  return candidates;
}

export function nextGeneration(cells: Cell[]): Cell[] {
  const survivors = cells.filter((cell) => {
    const neighborCount = countNeighbors(cell, cells);
    return neighborCount === 2 || neighborCount === 3;
  });

  const births = deadNeighborCandidates(cells).filter(
    (candidate) => countNeighbors(candidate, cells) === 3,
  );

  return [...survivors, ...births];
}

